  ('promotion-6acbf4ac-moex-00004', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'essay', '公務員得否於公餘時間兼任外送平台外送員？請從公務員服務法等相
關法令規定分析說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00005', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於不當聯結禁止原則之敘述，下列何者錯誤？', '["行政處分之附款應與該處分之目的具有正當合理之關聯", "人民與行政機關締結雙務行政契約時，人民之給付與行政機關之給付應相當，並具有正當合理 之關聯", "依司法實務見解，汽車所有人繳清違規罰鍰後始得換發行車執照，並未牴觸不當聯結禁止原則", "以同意捐款勞軍，作為核發建築許可之條件，牴觸不當聯結禁止原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00006', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '下列何者為行政法之一般法律原則？', '["依法行政原則", "罪刑法定原則", "契約自由原則", "不告不理原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00007', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '依司法院大法官解釋意旨，關於行政機關之判斷餘地，司法審查之範圍不包括下列何者？', '["行政機關之判斷，是否出於錯誤事實認定或不完全資訊", "法律概念涉及事實關係時，其涵攝有無明顯錯誤", "作成判斷之行政機關，其組織是否合法且有判斷之權限", "行政機關所為公務人員考績處分，是否符合其績效表現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL)
